"use client";
import { useState, useEffect, useRef } from "react";
import { Navigation, Play, Pause, RotateCcw, CheckCircle, AlertTriangle, Wind } from "lucide-react";
import { DRONE_ROUTES, OVERNIGHT_EVENTS } from "../lib/siteData";

const droneRoute = Object.values(DRONE_ROUTES)[0];

export default function DroneSimulator({ events, agentDone }) {
  const [playing, setPlaying] = useState(false);
  const [currentWaypoint, setCurrentWaypoint] = useState(0);
  const [completed, setCompleted] = useState(false);
  const [showObservations, setShowObservations] = useState(true);
  const intervalRef = useRef(null);

  const waypoints = droneRoute.waypoints;

  const reset = () => {
    setPlaying(false);
    setCurrentWaypoint(0);
    setCompleted(false);
    clearInterval(intervalRef.current);
  };

  useEffect(() => {
    if (playing && !completed) {
      intervalRef.current = setInterval(() => {
        setCurrentWaypoint(prev => {
          if (prev >= waypoints.length - 1) {
            setPlaying(false);
            setCompleted(true);
            clearInterval(intervalRef.current);
            return prev;
          }
          return prev + 1;
        });
      }, 1800);
    }
    return () => clearInterval(intervalRef.current);
  }, [playing, completed]);

  const currentObs = droneRoute.observations.filter(o => o.waypoint <= currentWaypoint);
  const nearbyEvents = events.filter(e => {
    const wp = waypoints[currentWaypoint];
    if (!wp) return false;
    const latDiff = Math.abs(e.coords[0] - wp.coords[0]);
    const lngDiff = Math.abs(e.coords[1] - wp.coords[1]);
    return latDiff < 0.008 && lngDiff < 0.008 && e.type !== "drone_patrol";
  });

  return (
    <div className="grid grid-cols-1 xl:grid-cols-3 gap-5">
      {/* Left panel: Route visualization */}
      <div className="xl:col-span-2">
        <div className="section-card">
          <div className="flex items-center gap-3 mb-4">
            <div className="w-8 h-8 rounded-lg flex items-center justify-center"
              style={{ background: "rgba(59,130,246,0.1)", border: "1px solid rgba(59,130,246,0.2)" }}>
              <Navigation size={16} className="animate-drone" style={{ color: "#3b82f6" }} />
            </div>
            <div>
              <h2 className="text-sm font-semibold" style={{ color: "var(--text-primary)" }}>
                Drone SD-7 · {droneRoute.name}
              </h2>
              <div className="text-xs" style={{ color: "var(--text-muted)" }}>
                {droneRoute.startTime} – {droneRoute.endTime} · Duration: 22 min · Altitude: 35m
              </div>
            </div>
            <div className="ml-auto flex items-center gap-2">
              <button onClick={() => { if (!completed) setPlaying(p => !p); }}
                disabled={completed}
                className="w-8 h-8 rounded-lg flex items-center justify-center transition-all"
                style={{
                  background: playing ? "rgba(59,130,246,0.15)" : "rgba(255,255,255,0.05)",
                  border: `1px solid ${playing ? "rgba(59,130,246,0.3)" : "var(--border-subtle)"}`,
                  color: "#3b82f6",
                }}>
                {playing ? <Pause size={14} /> : <Play size={14} />}
              </button>
              <button onClick={reset}
                className="w-8 h-8 rounded-lg flex items-center justify-center transition-all"
                style={{ background: "rgba(255,255,255,0.05)", border: "1px solid var(--border-subtle)", color: "var(--text-muted)" }}>
                <RotateCcw size={14} />
              </button>
            </div>
          </div>

          {/* Drone path visualization */}
          <div className="relative rounded-xl overflow-hidden mb-4"
            style={{ background: "var(--surface-0)", border: "1px solid var(--border-subtle)", height: 320 }}>
            {/* Grid overlay */}
            <div className="absolute inset-0 opacity-10"
              style={{
                backgroundImage: "linear-gradient(rgba(59,130,246,0.3) 1px, transparent 1px), linear-gradient(90deg, rgba(59,130,246,0.3) 1px, transparent 1px)",
                backgroundSize: "40px 40px"
              }} />

            {/* Site schematic */}
            <svg className="absolute inset-0 w-full h-full" viewBox="0 0 700 320">
              {/* Zone outlines */}
              <circle cx="180" cy="80" r="55" fill="rgba(59,130,246,0.05)" stroke="rgba(59,130,246,0.2)" strokeWidth="1" strokeDasharray="4 3" />
              <text x="180" y="78" textAnchor="middle" fill="#3b82f6" fontSize="10" opacity="0.6">Zone A</text>

              <circle cx="450" cy="130" r="65" fill="rgba(245,158,11,0.05)" stroke="rgba(245,158,11,0.2)" strokeWidth="1" />
              <text x="450" y="128" textAnchor="middle" fill="#f59e0b" fontSize="10" opacity="0.6">Zone B</text>

              <circle cx="300" cy="260" r="75" fill="rgba(239,68,68,0.05)" stroke="rgba(239,68,68,0.3)" strokeWidth="1.5" strokeDasharray="6 4" />
              <text x="300" y="258" textAnchor="middle" fill="#ef4444" fontSize="10" opacity="0.8">Zone C (Restricted)</text>

              <circle cx="350" cy="80" r="40" fill="rgba(16,185,129,0.05)" stroke="rgba(16,185,129,0.2)" strokeWidth="1" />
              <text x="350" y="78" textAnchor="middle" fill="#10b981" fontSize="9" opacity="0.6">Zone D</text>

              <circle cx="520" cy="50" r="50" fill="rgba(139,92,246,0.05)" stroke="rgba(139,92,246,0.2)" strokeWidth="1" />
              <text x="520" y="48" textAnchor="middle" fill="#8b5cf6" fontSize="9" opacity="0.6">Zone E</text>

              {/* Drone path */}
              {waypoints.map((wp, i) => {
                if (i >= waypoints.length - 1) return null;
                const next = waypoints[i + 1];
                const x1 = normalize(wp.coords[1], -0.098, -0.083, 50, 650);
                const y1 = normalize(wp.coords[0], 51.502, 51.512, 280, 30);
                const x2 = normalize(next.coords[1], -0.098, -0.083, 50, 650);
                const y2 = normalize(next.coords[0], 51.502, 51.512, 280, 30);
                const isActive = i < currentWaypoint;
                return (
                  <line key={i} x1={x1} y1={y1} x2={x2} y2={y2}
                    stroke={isActive ? "#3b82f6" : "rgba(59,130,246,0.2)"}
                    strokeWidth={isActive ? 2 : 1.5}
                    strokeDasharray={isActive ? "none" : "6 4"}
                    strokeLinecap="round"
                    style={{ transition: "stroke 0.5s, stroke-width 0.5s" }} />
                );
              })}

              {/* Event markers */}
              {events.filter(e => e.type !== "drone_patrol").map(event => {
                const x = normalize(event.coords[1], -0.098, -0.083, 50, 650);
                const y = normalize(event.coords[0], 51.502, 51.512, 280, 30);
                const colors = { high: "#ef4444", medium: "#f59e0b", low: "#10b981", info: "#3b82f6" };
                return (
                  <g key={event.id}>
                    <circle cx={x} cy={y} r="6" fill={colors[event.severity]} opacity="0.3" />
                    <circle cx={x} cy={y} r="4" fill={colors[event.severity]} opacity="0.8" />
                    <text x={x + 8} y={y + 4} fill={colors[event.severity]} fontSize="9" opacity="0.9">{event.time}</text>
                  </g>
                );
              })}

              {/* Drone waypoints */}
              {waypoints.map((wp, i) => {
                const x = normalize(wp.coords[1], -0.098, -0.083, 50, 650);
                const y = normalize(wp.coords[0], 51.502, 51.512, 280, 30);
                const isActive = i === currentWaypoint;
                const isPast = i < currentWaypoint;
                return (
                  <g key={i}>
                    {isActive && (
                      <circle cx={x} cy={y} r="16" fill="none" stroke="#3b82f6" strokeWidth="1" opacity="0.4">
                        <animate attributeName="r" from="10" to="20" dur="1.5s" repeatCount="indefinite" />
                        <animate attributeName="opacity" from="0.6" to="0" dur="1.5s" repeatCount="indefinite" />
                      </circle>
                    )}
                    <circle
                      cx={x} cy={y} r={isActive ? 8 : 5}
                      fill={isActive ? "#3b82f6" : isPast ? "rgba(59,130,246,0.5)" : "rgba(59,130,246,0.15)"}
                      stroke={isActive ? "#60a5fa" : "rgba(59,130,246,0.4)"}
                      strokeWidth="1.5"
                      style={{ transition: "all 0.5s" }}
                    />
                    {isActive && (
                      <text x={x} y={y - 14} textAnchor="middle" fill="#60a5fa" fontSize="9" fontWeight="600">
                        SD-7
                      </text>
                    )}
                    {!isActive && (
                      <text x={x + 8} y={y - 6} fill="rgba(59,130,246,0.5)" fontSize="8">
                        {i + 1}
                      </text>
                    )}
                  </g>
                );
              })}
            </svg>

            {/* Current position label */}
            <div className="absolute top-3 left-3 rounded-lg px-3 py-2"
              style={{ background: "rgba(13,17,23,0.92)", border: "1px solid rgba(59,130,246,0.2)" }}>
              <div className="text-xs font-medium" style={{ color: "#60a5fa" }}>
                {waypoints[currentWaypoint]?.label || "—"}
              </div>
              <div className="text-xs" style={{ color: "var(--text-muted)" }}>
                {waypoints[currentWaypoint]?.time || droneRoute.startTime}
              </div>
            </div>

            {/* Progress */}
            <div className="absolute bottom-3 left-3 right-3">
              <div className="flex justify-between text-xs mb-1" style={{ color: "var(--text-muted)" }}>
                <span>Waypoint {currentWaypoint + 1} / {waypoints.length}</span>
                <span style={{ color: "#60a5fa" }}>{Math.round((currentWaypoint / (waypoints.length - 1)) * 100)}%</span>
              </div>
              <div className="h-1 rounded-full" style={{ background: "rgba(59,130,246,0.15)" }}>
                <div className="h-full rounded-full transition-all duration-700"
                  style={{ width: `${(currentWaypoint / (waypoints.length - 1)) * 100}%`, background: "linear-gradient(90deg, #1d4ed8, #3b82f6)" }} />
              </div>
            </div>

            {completed && (
              <div className="absolute inset-0 flex items-center justify-center"
                style={{ background: "rgba(0,0,0,0.4)", backdropFilter: "blur(2px)" }}>
                <div className="rounded-xl px-6 py-4 text-center"
                  style={{ background: "var(--surface-2)", border: "1px solid rgba(16,185,129,0.3)" }}>
                  <CheckCircle size={24} className="mx-auto mb-2" style={{ color: "#6ee7b7" }} />
                  <div className="text-sm font-semibold" style={{ color: "var(--text-primary)" }}>Patrol Complete</div>
                  <div className="text-xs mt-1" style={{ color: "var(--text-muted)" }}>Night Loop Alpha – no anomalies detected</div>
                </div>
              </div>
            )}
          </div>
        </div>
      </div>

      {/* Right panel: Observations + Context */}
      <div className="flex flex-col gap-4">
        {/* Drone specs */}
        <div className="section-card">
          <div className="text-xs font-medium mb-3" style={{ color: "var(--text-secondary)" }}>Drone Status</div>
          <div className="space-y-2">
            {[
              { label: "Drone ID", value: "SD-7", color: "#3b82f6" },
              { label: "Route", value: "Night Loop Alpha", color: "#3b82f6" },
              { label: "Altitude", value: "35m", color: "#6ee7b7" },
              { label: "Sensors", value: "Thermal + Motion", color: "#6ee7b7" },
              { label: "Status", value: completed ? "Mission Complete" : playing ? "In Flight" : "Standby", color: completed ? "#6ee7b7" : playing ? "#f59e0b" : "#8b949e" },
            ].map(({ label, value, color }) => (
              <div key={label} className="flex items-center justify-between">
                <span className="text-xs" style={{ color: "var(--text-muted)" }}>{label}</span>
                <span className="text-xs font-medium" style={{ color }}>{value}</span>
              </div>
            ))}
          </div>
        </div>

        {/* Live observations */}
        <div className="section-card flex-1">
          <div className="text-xs font-medium mb-3" style={{ color: "var(--text-secondary)" }}>Field Observations</div>
          {currentObs.length === 0 ? (
            <div className="text-xs text-center py-4" style={{ color: "var(--text-muted)" }}>
              Start patrol to see observations
            </div>
          ) : (
            <div className="space-y-2">
              {currentObs.map((obs, i) => (
                <div key={i} className="rounded-lg px-3 py-2 animate-fade-in"
                  style={{ background: "rgba(16,185,129,0.06)", border: "1px solid rgba(16,185,129,0.2)" }}>
                  <div className="flex items-start gap-2">
                    <CheckCircle size={12} className="shrink-0 mt-0.5" style={{ color: "#6ee7b7" }} />
                    <span className="text-xs" style={{ color: "var(--text-secondary)" }}>{obs.text}</span>
                  </div>
                  <div className="text-xs mt-1" style={{ color: "var(--text-muted)" }}>
                    Waypoint {obs.waypoint + 1} · {waypoints[obs.waypoint]?.time}
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>

        {/* Timing gap warning */}
        {agentDone && (
          <div className="rounded-lg p-3"
            style={{ background: "rgba(245,158,11,0.05)", border: "1px solid rgba(245,158,11,0.2)" }}>
            <div className="flex items-center gap-2 mb-1">
              <AlertTriangle size={12} style={{ color: "var(--brand-amber)" }} />
              <span className="text-xs font-medium" style={{ color: "var(--brand-amber)" }}>
                Timing Gap – AI Note
              </span>
            </div>
            <p className="text-xs" style={{ color: "var(--text-muted)" }}>
              Vehicle event at Zone C occurred at 01:17. Drone reached Zone C at 03:48 — a 2.5 hour gap. The drone's clear observation does not negate the earlier vehicle detection.
            </p>
          </div>
        )}
      </div>
    </div>
  );
}

function normalize(val, min, max, outMin, outMax) {
  return outMin + ((val - min) / (max - min)) * (outMax - outMin);
}
